INSERT INTO `course_outcomes` (`id`, `course_id`, `name`, `name_en`, `created`, `updated`) VALUES
(1, 74, 'you can use the program easily and conveniently', 'يستطيع استخدام البرنامج بسهولة ويسر', '2024-11-06 12:01:06', '2024-11-06 12:01:06'),
(2, 74, 'Enables him to work as a data analyst in private or in an educational institution', 'يمكنه من العمل كمحلل للبيانات بصورة خاصه أو في احد المؤسسات التعليمية', '2024-11-06 12:01:59', '2024-11-06 12:02:08'),
(3, 2, NULL, 'Demonstrate knowledge of OSHA standards and General Duty Clauses', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(4, 2, NULL, 'Demonstrate a basic understanding of general safety & health provisions.', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(5, 2, NULL, 'Identify health hazards in construction.', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(6, 2, NULL, 'Demonstrate the basics of fall protection and prevention.', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(7, 2, NULL, 'Demonstrate electrical safety including lockout/tag-out and protective grounding equipment.', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(8, 2, NULL, 'Demonstrate overhead protection using identifying signs, signals, and barricades.', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(9, 2, NULL, 'Demonstrate proper material handling, rigging, storage, use, and disposal of most hazardous materials', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(10, 3, NULL, 'سيكون المتدرب ملما بكل اساسيات مفاهيم البرمجه', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(11, 3, NULL, 'سيكون المتدرب قادر علي تثبيت البايثون في اي جهاز ويندوز', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(12, 3, NULL, 'سيتعرف المتدرب علي بيئة البايثون ويكون قادر علي التعامل مع اكواد البايثون بكل سهولة', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(13, 3, NULL, 'سيكون المتدرب ملما بكل انواع البيانات في البايثون', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(14, 3, NULL, 'سيكون المتدرب قادرا علي كتابة جمل برمجيه باستخدام البايثون تؤدي غرضا محددا', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
(15, 3, NULL, 'سيكون المتدرب قادرا علي استخدام حلقات التكرار والجمل الشرطيه في البايثون بكل سلاسه', '2024-11-19 20:37:40', '2024-11-19 20:37:40'),
