INSERT INTO `live_participation_types` (`id`, `title`, `title_ar`, `descr`, `descr_ar`) VALUES
(1, 'Text Messages Only', 'رسائل نصية فقط', '\r\nYou can send text messages that the trainer can also see and respond to during the live broadcast', 'يمكنك ارسال رسائل نصية يمكن للمدرب أيضا أن يشاهدها ويرد عليها أثناء البث الحي'),
(2, '\r\nOne person at intervals determined by the trainer\r\n', 'شخص واحد في فترات زمنية يحددها المدرب', 'The trainer opens participation in certain periods during the live broadcast, and everyone can request participation and acceptance is by the trainer', 'يقوم المدرب بفتح المشاركة في فترات معينة أثناء البث الحي ويمكن للجميع طلب المشاركة ويكون القبول بواسطة المدرب'),
(3, '\r\nEveryone at intervals determined by the trainer', 'الجميع في فترات زمنية يحددها المدرب', 'The trainer opens participation in certain periods during the live broadcast, and everyone can participate without prior request', 'يقوم المدرب بفتح المشاركة في فترات معينة أثناء البث الحي ويمكن للجميع المشاركة بدون طلب مسبق\r\n'),
(4, 'Voice participation is always allowed', 'يُسمح دائمًا بالمشاركة الصوتية', 'Anyone can participate at any time throughout the live broadcast', 'يمكن لأي شخص المشاركة في أي وقت طوال فترة البث الحي');
