INSERT INTO `workshops` (`id`, `name`, `name_ar`, `workshop_type_id`, `trainer_id`, `img`, `pre_req`, `pre_req_ar`, `descr`, `descr_ar`, `tot_hours`, `lecture_hours`, `lecture_count`, `corporation_sdg_price`, `total_parts`, `completed_parts`, `hash`, `online_total_parts`, `online_completed_parts`, `online_hash`, `online_processed`, `level`, `outcome`, `outline`, `logo`, `outcome_ar`, `line_descr`, `line_descr_ar`, `short_descr`, `short_descr_ar`, `trainer_online_percent`, `created`, `updated`) VALUES
(12, 'Full Stack Web', 'مبرمح الويب الكامل', 2, 11, '12.png', '[]', '[]', '\r\nBecome a full stack web developer and learn to design and develop powerful modern web applications that form the foundation for apps and websites', 'كن مطور ويب متكامل وتعلم تصميم وتطوير تطبيقات ويب حديثة قوية تشكل الأساس للتطبيقات والمواقع الإلكترونية\r\n', NULL, NULL, NULL, '25000.000', 1, 1, 'undefined', NULL, 0, NULL, 0, 1, '[]', '[]', NULL, '[]', 'This is line description of the workshop', 'هذا هو وصف الورشة', 'this is a short description of the workshop. It should fit the area on the website or the mobile application', 'هذا وصف موجز لورشة العمل. يجب أن تتناسب مع المنطقة الموجودة على موقع الويب أو تطبيق الهاتف المحمول', 55, '2021-03-07 09:12:57', '2025-03-07 14:16:41'),
(13, 'Active Learning', 'التعلم النشط', 1, 11, '13.jpg', '[]', '[]', '<p>-</p>', '<p>هدف هذه الدورة إلى تمكين الدارس من التعرف على التعلم الفعال \"وكيف نقوم بتفعيل عملية التعلم ونقل الطالب من مرحلة المستقبل السلبي للمعلومة إلى مرحلة الباحث والمستكشف للمعلومة وعليه يتحول دور المعلم من مصدر وحيد للمعلومة لموجه وميسر لعملية حصول الطالب على المعلومة\"، باللإضافة إلى كيفية تفعيل عمليتي التعليم والتعلم لدى المعلم والطالب من خلال تمكينه من التعرف على الأنشطة التعيلمية المختلفة والتمكن من تطبيقها\" هنا يتم تمكين المعلم من الأنشطة والأساليب الخاصة بتفعيل دور الطلبة وتمكينه من إدارة هذه الأنشطة لتحقيق أهداف التعلم\"، إضافة إلى كيفية صياغة الأهداف التعليمية بأنواعها الثلاثة وجميع المستويات الخاصة بكل نوع منها\" للبدء بالحصة الصفية بشكل سليم واختيار الأنشطة التي تحقق هذه الأهداف وبناء عليه تحدد الأدوار التي سيقوم بها كل من المعلم والطالب في هذه الأنشطة\"، لكي يعي المعلم الأدوار الجديدة له وللطالب وتمكينه من الأدوار الجديدة في التعلم النشط، وكذلك تمكين الدارس من إدارة الغرفة الصفية في التعلم النشط بما يخدم ويحقق الأهداف التعليمية المخطط لها عن طريق السير\"بإجراءات واضحة ومحددة تتمثل فيما يسمى دورة التعلم الخماسية والتي توضح للمعلم كيفية السير في الحصة الصفية لتحقيق جميع أهدافها وكيفية تأثيرها على تفعيل الحصة الصفية والخروج من دور المرسل للمعلم والمتلقي السلبي للطالب\"، وكيفية توجيه عمليتي التعليم والتعلم في سبيل تحقيق الأهداف التعليمية.</p>', NULL, NULL, NULL, '13000.000', 0, 1, 'undefined', NULL, 0, NULL, 0, 1, '[]', '[]', NULL, '[]', 'This is line description of the workshop', 'هذا هو وصف الورشة', 'this is a short description of the workshop. It should fit the area on the website or the mobile application', 'هذا وصف موجز لورشة العمل. يجب أن تتناسب مع المنطقة الموجودة على موقع الويب أو تطبيق الهاتف المحمول', 0, '2022-03-06 08:16:38', '2025-03-03 09:58:22'),
(14, 'Internet of Things', 'إنترنت الأشياء', 1, 10, '14.png', '[]', '[]', 'The Internet of things (IoT) describes physical objects with sensors, processing ability, software, and other technologies that connect and exchange data ', 'يصف إنترنت الأشياء (IoT) الأشياء المادية بأجهزة الاستشعار وقدرة المعالجة والبرامج والتقنيات الأخرى التي تربط البيانات وتتبادلها', NULL, NULL, NULL, '0.000', 1, 1, 'undefined', NULL, 0, NULL, 0, 2, '[]', '[]', NULL, '[]', 'This is line description of the workshop', 'هذا هو وصف الورشة', 'this is a short description of the workshop. It should fit the area on the website or the mobile application', 'هذا وصف موجز لورشة العمل. يجب أن تتناسب مع المنطقة الموجودة على موقع الويب أو تطبيق الهاتف المحمول', 0, '2021-07-07 09:12:57', '2025-03-03 10:01:07'),
(15, 'الكترونيات', 'الكترونيات', 3, 11, '15.jpg', '[]', '[]', '<p>الكترونيات</p>', '<p>الكترونيات</p>', NULL, NULL, NULL, '0.000', NULL, 0, NULL, NULL, 0, NULL, 0, 2, '[]', '[]', NULL, '[]', 'This is line description of the workshop', 'هذا هو وصف الورشة', 'this is a short description of the workshop. It should fit the area on the website or the mobile application', 'هذا وصف موجز لورشة العمل. يجب أن تتناسب مع المنطقة الموجودة على موقع الويب أو تطبيق الهاتف المحمول', 0, '2022-09-20 08:26:59', '2025-03-03 10:01:04'),
(26, 'sdbhscdm', 'jmksdfcklsdcf', 3, 11, NULL, '[]', '[]', '<p>dvdjmkl</p>', '<p>sdnjk</p>', NULL, NULL, NULL, '0.000', NULL, 0, NULL, NULL, 0, NULL, 0, 1, '[]', '[]', NULL, '[]', 'This is line description of the workshop', 'هذا هو وصف الورشة', 'this is a short description of the workshop. It should fit the area on the website or the mobile application', 'هذا وصف موجز لورشة العمل. يجب أن تتناسب مع المنطقة الموجودة على موقع الويب أو تطبيق الهاتف المحمول', 1, '2022-09-20 15:08:27', '2025-03-03 10:00:58'),
(27, 'fullstack web Development', 'تطوير الويب', 1, 11, '1732604309200606.png', '[]', '[]', 'لا', 'لا', NULL, NULL, NULL, '0.000', 109, 109, '5a04d3bfd2d80691df62695e331be8f7', 109, 109, '5a04d3bfd2d80691df62695e331be8f7', 1, 1, '[\"لا\"]', '[]', NULL, '[]', 'This is line description of the workshop', 'هذا هو وصف الورشة', 'this is a short description of the workshop. It should fit the area on the website or the mobile application', 'هذا وصف موجز لورشة العمل. يجب أن تتناسب مع المنطقة الموجودة على موقع الويب أو تطبيق الهاتف المحمول', 30, '2022-09-24 12:02:27', '2025-03-03 10:38:19'),
(28, 'ujsuj', 'dnmwjq', 4, 10, '_1664282419132.jpg', '[\"djnqwd\"]', '[\"djnhwdn\"]', '<p>djnwn	</p>', '<p>dnjqk</p>', NULL, NULL, NULL, '0.000', 1, 0, 'a8226f0fd507c94f30d64e38b25170da', NULL, 0, NULL, 0, 1, '[\"djmwdk\"]', '[\"xwsdn\"]', '_1664352400594.jpg', '[\"jndqw\"]', 'This is line description of the workshop', 'هذا هو وصف الورشة', 'this is a short description of the workshop. It should fit the area on the website or the mobile application', 'هذا وصف موجز لورشة العمل. يجب أن تتناسب مع المنطقة الموجودة على موقع الويب أو تطبيق الهاتف المحمول', 20, '2022-09-27 12:40:19', '2025-10-14 11:20:29'),
(29, 'الكترونيات', 'الكترونيات', 1, 11, '_1664354309654.jpg', '[\"snj\"]', '[\"snms\"]', '<p>xjhhs</p>', '<p>sk</p>', NULL, NULL, NULL, '0.000', 1, 0, 'a8226f0fd507c94f30d64e38b25170da', 4, 4, '17ce88f4667423bf589106dcd70d70f5', 1, 1, '[\"xwj\"]', '[\"sn\"]', '_1664354309655.jpg', '[\"sj\"]', 'This is line description of the workshop', 'هذا هو وصف الورشة', 'this is a short description of the workshop. It should fit the area on the website or the mobile application', 'هذا وصف موجز لورشة العمل. يجب أن تتناسب مع المنطقة الموجودة على موقع الويب أو تطبيق الهاتف المحمول', 10, '2022-09-28 08:38:29', '2025-03-03 11:10:34'),
(30, 'Practical network configuration', 'ورشة تركيب الشبكات العمليه', 4, 10, '1760439972249150.png', '[\"Network fundamental\",\"OSI model\",\"IPv4\"]', '[\"أساسيات الشبكات\",\"OSI model\",\"IPv4\"]', '<p>The workshop will start with knowing the science of networking and networking companies and defining an orientation for students so that each of them begins in his exact specialization, then we move on to network components, then network devices, as well as types of connecting cable, moving to the terminal blocks of the network, and the method of arranging on the trunks to the rack and connecting switches with routers with Internet devices, and so on. Forging all vinyl\'s for installation and lathe operations, and the AutoCAD program for design.</p>', '<p class=\"ql-direction-rtl ql-align-right\">ستبدا الورشه&nbsp;بمعرفه علم الشبكات وشركات الشبكات وتحديد&nbsp;توجه للطلاب لكي يبدا كل منه في تخصصه الدقيق ثم ننتقل الى مكونات الشبكه ثم اجهزة الشبكه وكذلك انواع الكيبل الموصل انتقالا الى بلكات اطراف الشبكه وطريقه الترتيب على الترنك وصولا الى الراك وربط السويتشات مع الراوترات مع اجهزة الانترنت وهكذا &nbsp;ثم التطريق لكل الفنيلت الخاصه بعمليات التركيب والخرط وبرنامج الاوتكاد الخاص بالتصميم .</p><p class=\"ql-direction-rtl ql-align-right\"><br></p>', 120, 4, NULL, '0.000', 4, 4, '4b930179bd81b2290c244c26d02cab3e', 28, 28, 'bd58530b5102edd7642a19b55bd85e32', 1, 2, '[\"After completing the workshop, the student will be able to make basic settings on routers and switches, connect them, and be able to identify and solve problems.\"]', '[\"Introduction to networks\", \"Networking basics\", \"Networking companies\", \"Network concepts\", \"networking\", \"trunking\", \"cabling\"]', NULL, '[\"بعد الانتهاء من الورشه يكون الطالب قادر على عمل الإعدادات الأساسية على الراوترات و السويتشات و توصيلها و المقدرة على تحديد و حل المشاكل\"]', 'You will learn everything related to network installation operations', 'ستتعلم  كل ما يختص بعمليات تركيب الشبكات', 'Practical and theoretical training on how to set up, connect and solve problems on Cisco routers and switches.', 'تدريب عملي ونظري على طريقة اعداد وتوصيل وحل المشاكل على راوترات وسويتشات سيسك', 15, '2022-09-29 19:18:47', '2025-10-14 11:19:39'),
