INSERT INTO `workshop_outcomes` (`id`, `workshop_id`, `name`, `name_en`, `created`, `updated`) VALUES
(1, NULL, 'you can use the program easily and conveniently', 'يستطيع استخدام البرنامج بسهولة ويسر', '2024-11-06 12:01:06', '2025-04-01 18:24:17'),
(2, NULL, 'Enables him to work as a data analyst in private or in an educational institution', 'يمكنه من العمل كمحلل للبيانات بصورة خاصه أو في احد المؤسسات التعليمية', '2024-11-06 12:01:59', '2025-04-01 18:24:26'),
(3, 27, NULL, 'لا', '2024-11-19 21:17:51', '2024-11-19 21:17:51'),
(4, 28, 'jndqw', 'djmwdk', '2024-11-19 21:17:51', '2024-11-19 21:17:51'),
(5, 29, 'sj', 'xwj', '2024-11-19 21:17:51', '2024-11-19 21:17:51'),
(7, 14, 'مفاهيم إنترنت الأشياء – فهم المفاهيم الأساسية، الهيكلية، والتطبيقات الواقعية لإنترنت الأشياء.', 'Fundamentals of IoT – Understand the core concepts, architecture, and real-world applications of IoT.', '2025-04-01 18:29:32', '2025-04-01 18:41:19'),
(8, 14, 'تطوير أجهزة إنترنت الأشياء عمليًا – تعلم كيفية بناء وبرمجة أجهزة إنترنت الأشياء باستخدام المتحكمات الدقيقة والمستشعرات.', 'Hands-on IoT Development – Learn to build and program IoT devices using microcontrollers and sensors.', '2025-04-01 18:29:58', '2025-04-01 18:41:35'),
(9, 14, 'الاتصال والتواصل – استكشاف بروتوكولات الاتصال في إنترنت الأشياء مثل MQTT و HTTP و WebSockets.', 'Connectivity & Communication – Explore IoT communication protocols like MQTT, HTTP, and WebSockets.', '2025-04-01 18:41:47', '2025-04-01 18:41:47'),
(10, 14, 'التكامل مع السحابة – اكتشاف كيفية توصيل أجهزة إنترنت الأشياء بالمنصات السحابية لتخزين البيانات والوصول إليها عن بُعد.', 'Cloud Integration – Discover how to connect IoT devices to cloud platforms for data storage and remote access.', '2025-04-01 18:42:00', '2025-04-01 18:42:00'),
