DROP PROCEDURE IF EXISTS `arraySummer`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `arraySummer` (OUT `tot` INT)   BEGIN
declare t,i int DEFAULT 0;
declare arr json;
select json_arrayagg(id) into arr from students_users;
select arr;
myLoop: while i<json_length(arr) DO
set t=t+json_extract(arr,concat('$[',i,']'));
set i=i+1;
end while myLoop;
set tot=t;
end$$

DROP PROCEDURE IF EXISTS `buyItem`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `buyItem` (INOUT `bal` FLOAT, IN `price` FLOAT, IN `qty` INT, OUT `status` VARCHAR(255))   BEGIN

declare total_bill float DEFAULT 0.0;
set total_bill=qty*price;
if bal>=total_bill THEN
  set bal=bal-total_bill;
  case total_bill
  when 10000 then set status='premium';
  when 5000 then set status='silver';
  else BEGIN end;
  end CASE;
end if;



end$$

DROP PROCEDURE IF EXISTS `calcExamProc`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `calcExamProc` (IN `course_reg_id_var` INT, IN `course_exam_id_var` INT)   BEGIN
    DECLARE finished,answer_id,num_answer,check_created,loop_index,loop_count,correct_count INTEGER DEFAULT 0;
    DECLARE tot_degree,student_degree,q_degree_var,st_degree_var float DEFAULT 0;
     DECLARE exam_cursor CURSOR FOR SELECT a.id,q.degree as q_degree,a.degree as st_degree
	FROM courses_exams_questions q
	LEFT JOIN courses_exams_answers a on q.id = a.courses_exams_questions_id and  a.course_reg_id=course_reg_id_var
	WHERE courses_exams_id= course_exam_id_var;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET finished = 1;
    
SELECT count(*) into num_answer
	FROM courses_exams_questions q
	JOIN courses_exams_answers a on q.id = a.courses_exams_questions_id and  a.course_reg_id=course_reg_id_var
	WHERE courses_exams_id= course_exam_id_var;
   SELECT num_answer;
   if num_answer=0 THEN
      else
   
   
    set finished=0;
    open exam_cursor;
    checkAllAnswers:LOOP
		FETCH exam_cursor INTO answer_id,q_degree_var,st_degree_var;
		
        IF finished = 1 THEN 
            SELECT "Done";
			LEAVE checkAllAnswers;
		END IF;
		set tot_degree=tot_degree+q_degree_var;
        if student_degree is not null then
       	   set student_degree=student_degree+st_degree_var;  
        end if;
	END LOOP checkAllAnswers;
    SELECT count(*) into check_created from courses_exams_check where course_exam_id=course_exam_id_var and course_reg_id=course_reg_id_var;
    if check_created>0 THEN
