DROP PROCEDURE IF EXISTS `CalculateCourseQuizDegree`$$
CREATE DEFINER=`root`@`%` PROCEDURE `CalculateCourseQuizDegree` (IN `course_reg_id_var` INT)   BEGIN
    DECLARE finished, answer_id, num_answer, loop_index, loop_count, correct_count INTEGER DEFAULT 0;
    DECLARE tot_degree, student_degree, q_degree_var, st_degree_var FLOAT DEFAULT 0;
    DECLARE course_quiz_id_var INT;

    DECLARE exam_cursor CURSOR FOR
        SELECT
            a.id,
            q.degree AS q_degree,
            a.degree AS st_degree,
            q.id AS course_quiz_id
        FROM
            courses_quizzes q
            LEFT JOIN courses_quizz_answers a ON q.id = a.courses_quizz_id
        WHERE a.course_reg_id = course_reg_id_var;

    DECLARE CONTINUE HANDLER FOR NOT FOUND
        SET finished = 1;

    -- Update degrees in courses_quizz_answers and is_correct flag
    UPDATE courses_quizz_answers a
    JOIN courses_quizzes q ON a.courses_quizz_id = q.id
    SET a.degree = IF(a.answer = q.answer, q.degree, 0),
        a.is_correct = IF(a.answer = q.answer, 1, 0)
    WHERE a.course_reg_id = course_reg_id_var;


    SELECT COUNT(*) INTO num_answer
    FROM courses_quizzes q
    JOIN courses_quizz_answers a ON q.id = a.courses_quizz_id
    WHERE a.course_reg_id = course_reg_id_var;

    IF num_answer = 0 THEN
        -- Handle the case where no answers are found (optional)
        SELECT 'No answers found for this course registration'; -- Or update a table with a default value.
    ELSE
        SET finished = 0;
        SET tot_degree = 0;
        SET student_degree = 0;

        OPEN exam_cursor;

        checkAllAnswers:LOOP
            FETCH exam_cursor INTO answer_id, q_degree_var, st_degree_var, course_quiz_id_var;

            IF finished = 1 THEN
                LEAVE checkAllAnswers;
            END IF;

            SET tot_degree = tot_degree + q_degree_var;
            SET student_degree = student_degree + COALESCE(st_degree_var, 0); -- Use COALESCE to handle NULLs

        END LOOP checkAllAnswers;

        CLOSE exam_cursor;

        -- Calculate and potentially update the degree somewhere.  You'll need a table to store this.
        -- Example: Assuming you have a `course_registrations` table with a `final_grade` column:

        UPDATE course_registrations
        SET final_grade = (student_degree / tot_degree) * 100  -- or just student_degree if that's what you want.
        WHERE id = course_reg_id_var;

    END IF;

END$$

DROP PROCEDURE IF EXISTS `CalculatePlacementTestDegree`$$
CREATE DEFINER=`root`@`%` PROCEDURE `CalculatePlacementTestDegree` (IN `placement_test_process_id_var` INT)   BEGIN DECLARE finished,
answer_id,
num_answer,

loop_index,
loop_count,
correct_count INTEGER DEFAULT 0;

DECLARE tot_degree,
student_degree,
q_degree_var,
st_degree_var float DEFAULT 0;

DECLARE exam_cursor CURSOR FOR
SELECT
    a.id,
    q.degree as q_degree,
    a.degree as st_degree
FROM
    placement_test_questions q
    LEFT JOIN placement_test_answers a on q.id = a.placement_test_question_id
    and a.placement_test_process_id = placement_test_process_id_var;

DECLARE CONTINUE HANDLER FOR NOT FOUND
SET
    finished = 1;

-- Update degrees in placement_test_answers
UPDATE
    placement_test_answers a
    JOIN placement_test_questions q ON a.placement_test_question_id = q.id
SET
    a.degree = if(a.answer = q.answer, q.degree, 0)
WHERE
    a.placement_test_process_id = placement_test_process_id_var;

SELECT
    count(*) into num_answer
FROM
    placement_test_questions q
    JOIN placement_test_answers a on q.id = a.placement_test_question_id
    and a.placement_test_process_id = placement_test_process_id_var;

SELECT
    num_answer;

if num_answer = 0 THEN
update
    placement_test_processes
set
    degree = 0
where
    id = placement_test_process_id_var;

else
set
    finished = 0;

SET
    tot_degree = 0;

SET
    student_degree = 0;

open exam_cursor;

checkAllAnswers :LOOP FETCH exam_cursor INTO answer_id,
q_degree_var,
st_degree_var;

IF finished = 1 THEN
SELECT
    "Done";

LEAVE checkAllAnswers;

END IF;

set
    tot_degree = tot_degree + q_degree_var;

SELECT
    student_degree,
    st_degree_var;

if student_degree is not null then
set
    student_degree = student_degree + coalesce(st_degree_var, 0);

end if;

END LOOP checkAllAnswers;

CLOSE exam_cursor;

SELECT
    student_degree,
    tot_degree;

update
    placement_test_processes
set
    degree =(student_degree / tot_degree) * 100
where
    id = placement_test_process_id_var;

end if;

END$$

