DROP PROCEDURE IF EXISTS `finishAllOnlineStudents`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `finishAllOnlineStudents` ()  NO SQL BEGIN
    DECLARE course_reg_id_var,days_count,student_id_var,total_course_videos,running_course_id_var,courses_finished,project_index,projects_count,exam_index,exams_count,question_index,questions_count,reg_type_var int DEFAULT 0;
