	select sum(amount) into tot_usd_offline from courses_reg join accounting on courses_reg.id=accounting.details_id where running_course_id=running_course_id_var and currency='d' and accounting.type_id=1 and reg_type=1 and cancelled=0 and courses_reg.payment_confirmed=1 and amount>0;
	select sum(amount) into tot_usd_online from courses_reg join accounting on courses_reg.id=accounting.details_id where running_course_id=running_course_id_var and currency='d' and accounting.type_id=1 and reg_type=2 and cancelled=0 and courses_reg.payment_confirmed=1 and amount>0;
	select sum(amount) into tot_sdg_offline from courses_reg join accounting on courses_reg.id=accounting.details_id where running_course_id=running_course_id_var and currency='s' and accounting.type_id=1 and reg_type=1 and cancelled=0 and courses_reg.payment_confirmed=1 and amount>0;
	select sum(amount) into tot_sdg_online from courses_reg join accounting on courses_reg.id=accounting.details_id where running_course_id=running_course_id_var and currency='s' and accounting.type_id=1 and reg_type=2 and cancelled=0 and courses_reg.payment_confirmed=1 and amount>0;
	
	update running_courses set teacher_deserves_usd=(if(tot_usd_offline,tot_usd_offline,0)*percent_offline_var/100+if(tot_usd_online,tot_usd_online,0)*percent_online_var/100),teacher_deserves=(if(tot_sdg_offline,tot_sdg_offline,0)*percent_offline_var/100+if(tot_sdg_online,tot_sdg_online,0)*percent_online_var/100),calcualted=1,calculated_time=CURRENT_TIMESTAMP where id=running_course_id_var;
    
	
	COMMIT;
END$$

