DROP PROCEDURE IF EXISTS `finishStudentCourses`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `finishStudentCourses` (IN `student_id_var` INT)  NO SQL BEGIN
    DECLARE course_reg_id_var,days_count,running_course_id_var,courses_finished,project_index,projects_count,exam_index,exams_count,question_index,questions_count,reg_type_var int DEFAULT 0;
    DECLARE course_name text;
    DECLARE course_degree,exams_percent,projects_percent,tot_projects_degree,got_projects_degree,tot_exams_degree,got_exams_degree,attendance_percent,watch_percent float DEFAULT 0;
    declare exams_var,projects_var json;
	DECLARE percent_online_var,percent_offline_var,tot_sdg_online,tot_sdg_offline,tot_usd_online,tot_usd_offline float default 0;

    DECLARE courses_cursor CURSOR FOR SELECT courses_reg.id,running_course_id,reg_type from courses_reg where student_id=student_id_var and payment_confirmed=1 and cancelled=0;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET courses_finished = 1;
	
	
	DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
	    GET DIAGNOSTICS CONDITION 1
        @p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
        SELECT @p1 as RETURNED_SQLSTATE  , @p2 as MESSAGE_TEXT;
        ROLLBACK;
    END;
	
	
	 START TRANSACTION;
	
    open courses_cursor;
    courses_loop: LOOP
	
        
		
		FETCH courses_cursor INTO course_reg_id_var,running_course_id_var,reg_type_var;
		
		
       
        IF courses_finished = 1 THEN 
			LEAVE courses_loop;
		END IF;
         SELECT concat('student ',(select name from users where id=student_id_var));

		
		
		
		
        SELECT json_arrayagg(json_object('q_degree',courses_projects.degree,'st_degree',courses_projects_uploads.degree)) into projects_var  from courses_projects left join courses_projects_uploads on courses_projects.id=courses_projects_uploads.courses_projects_id and  course_reg_id=course_reg_id_var where running_course_id=running_course_id_var and courses_projects.cancelled=0;
        
		
		
		
        SELECT json_arrayagg(json_object('st_degree',courses_exams_check.degree)) into exams_var  from courses_exams left join courses_exams_check on courses_exams.id=courses_exams_check.course_exam_id and  course_reg_id=course_reg_id_var where running_course_id=running_course_id_var and courses_exams.cancelled=0;
        
        
        if json_length(exams_var)=0 and json_length(projects_var)=0 THEN
        SELECT "Without Exams";
    else
        
		set got_projects_degree=0;
        set tot_projects_degree=0;
        
		
		set got_exams_degree=0;
        set tot_exams_degree=0;
        
        select projects_var;
        set projects_count=json_length(projects_var);
        set project_index=0;
        select projects_count;
		
		
        while project_index<projects_count DO
            if json_extract(projects_var,concat("$[",project_index,"].st_degree")) then
		        set got_projects_degree=got_projects_degree+json_extract(projects_var,concat("$[",project_index,"].st_degree"));     		  
		    end if;
            set tot_projects_degree=tot_projects_degree+json_extract(projects_var,concat("$[",project_index,"].q_degree"));
			set project_index=project_index+1;
        end while;
        select concat("total projects degree is ",tot_projects_degree);
        select concat("got projects degree is ",got_projects_degree);
        
		select exams_var;
        set exams_count=json_length(exams_var);
        set exam_index=0;
        select exams_count;
		
		
        while exam_index<exams_count DO
            if json_extract(exams_var,concat("$[",exam_index,"].st_degree")) then
		        set got_exams_degree=got_exams_degree+json_extract(exams_var,concat("$[",exam_index,"].st_degree"));     		  
		    end if;
            set tot_exams_degree=tot_exams_degree+100;
			set exam_index=exam_index+1;
        end while;
        select concat("total exams degree is ",tot_exams_degree);
        select concat("got exams degree is ",got_exams_degree);		
		
		select course_reg_id_var;
		if tot_exams_degree=0 then
		    set exams_percent=100;
		else 
		    set exams_percent=(got_exams_degree/tot_exams_degree)*exams_count/(exams_count+projects_count);
		end if;
		if tot_projects_degree=0 then
		    set projects_percent=100;
		else 
		    set projects_percent=(got_projects_degree/tot_projects_degree)*projects_count/(exams_count+projects_count);
			end if;
		set course_degree=(exams_percent+projects_percent)*100;
        SELECT course_degree;
		update courses_reg set degree=course_degree,cert_deserve=if(course_degree>=(SELECT 	min_success from running_courses where id=running_course_id_var),1,0),not_desrve_reason=if(course_degree>=(SELECT 	min_success from running_courses where id=running_course_id_var),null,'d') where id=course_reg_id_var;
        
        end if;
        	
        
        
        
       if reg_type_var=1 THEN
	              SELECT count(DISTINCT date) into days_count FROM courses_attendance where running_course_id=running_course_id_var;
		   if days_count!=0 then
           SELECT (SELECT count(*) from courses_attendance where running_course_id=running_course_id_var and course_reg_id=course_reg_id_var)/count(DISTINCT date) into attendance_percent FROM courses_attendance where running_course_id=running_course_id_var;
			else 
           set attendance_percent=1;
		   end if;
           SELECT attendance_percent;
           
           
           if json_length(exams_var)=0 and json_length(projects_var)=0 THEN
           update courses_reg set cert_deserve=if(attendance_percent>=(SELECT value from atc_config where title='attendance_rate'),1,0),not_desrve_reason=if(attendance_percent>=(SELECT value from atc_config where title='attendance_rate'),null,'a') where id=course_reg_id_var;
           else
           update courses_reg set cert_deserve=if(attendance_percent>=(SELECT value from atc_config where title='attendance_rate') and course_degree>=(SELECT 	min_success from running_courses where id=running_course_id_var),1,0),not_desrve_reason=if(attendance_percent>=(SELECT value from atc_config where title='attendance_rate') and course_degree>=(SELECT 	min_success from running_courses where id=running_course_id_var),null,if(course_degree<(SELECT 	min_success from running_courses where id=running_course_id_var),'d','a')) where id=course_reg_id_var;
           end if;
           
           
           ELSE
           
            
          
		  
select 
   
 (select count(*) from video_pathes where tot_video_cues(id)>0 and watched_video_cues(id,course_reg_id_var)/tot_video_cues(id)>=(select value from atc_config where title='video_watch_rate') and course_video_id in (select course_video_id from course_lecture_videos where course_lecture_id in (select id from courses_lectures where running_course_id=running_course_id_var)))
		   / 
		   get_total_videos(running_course_id_var)  
		   into watch_percent;
           
           
           
           
           if json_length(exams_var)=0 and json_length(projects_var)=0 THEN
           update courses_reg set cert_deserve=if(watch_percent>=(SELECT value from atc_config where title='course_watch_rate'),1,0),not_desrve_reason=if(watch_percent>=(SELECT value from atc_config where title='course_watch_rate'),null,'w') where id=course_reg_id_var;
           else
           update courses_reg set cert_deserve=if(watch_percent>=(SELECT value from atc_config where title='course_watch_rate') and course_degree>=(SELECT 	min_success from running_courses where id=running_course_id_var),1,0),not_desrve_reason=if(attendance_percent>=(SELECT value from atc_config where title='course_watch_rate') and course_degree>=(SELECT min_success from running_courses where id=running_course_id_var),null,if(course_degree<(SELECT min_success from running_courses where id=running_course_id_var),'d','w')) where id=course_reg_id_var;
           end if;
           update courses_reg set watch_rate=watch_percent where id=course_reg_id_var;
       end if;
        
       
       
       
	END LOOP courses_loop;
	
	select "All courses finished";
	
	

	
	COMMIT;
END$$

DROP PROCEDURE IF EXISTS `finishStudentWorkshops`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `finishStudentWorkshops` (IN `student_id_var` INT)  NO SQL BEGIN
    DECLARE workshop_reg_id_var,running_workshop_id_var,workshops_finished,reg_type_var int DEFAULT 0;
    DECLARE workshop_name text;
    DECLARE watch_percent float DEFAULT 0;


    DECLARE workshops_cursor CURSOR FOR SELECT workshops_reg.id,running_workshop_id,reg_type from workshops_reg where student_id=student_id_var and payment_confirmed=1 and cancelled=0;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET workshops_finished = 1;
	
	
	DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
	    GET DIAGNOSTICS CONDITION 1
        @p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
        SELECT @p1 as RETURNED_SQLSTATE  , @p2 as MESSAGE_TEXT;
        ROLLBACK;
    END;
	
	
	 START TRANSACTION;
	
    open workshops_cursor;
    workshops_loops:LOOP
	
        
		
		FETCH workshops_cursor INTO workshop_reg_id_var,running_workshop_id_var,reg_type_var;
		
		
       
        IF workshops_finished = 1 THEN 
			LEAVE workshops_loops;
		END IF;
	
        
        
       if reg_type_var=2 THEN
  
select 
   
 (select count(*) from workshop_cues_watch where workshop_reg_id = workshop_reg_id_var) /
								  (select count(*)
								   from workshop_cues
								   where running_workshop_id = running_workshop_id_var) 
		   into watch_percent;
           
           
           
           
            update workshops_reg set cert_deserve=if(watch_percent>=(SELECT value from atc_config where title='workshop_watch_rate'),1,0) where id=workshop_reg_id_var;
       end if;
        
       
       
       
	END LOOP workshops_loops;
	
	select "All students finished";
	
	COMMIT;
END$$

DROP PROCEDURE IF EXISTS `finishWorkshop`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `finishWorkshop` (IN `running_workshop_id_var` INT)  NO SQL BEGIN
    DECLARE workshop_reg_id_var,student_id_var,students_finished,reg_type_var int DEFAULT 0;
    DECLARE workshop_name text;
    DECLARE watch_percent float DEFAULT 0;
	DECLARE percent_online_var,percent_offline_var,tot_sdg_online,tot_sdg_offline,tot_usd_online,tot_usd_offline float default 0;

    DECLARE students_cursor CURSOR FOR SELECT workshops_reg.id,student_id,reg_type from workshops_reg where running_workshop_id=running_workshop_id_var and payment_confirmed=1 and cancelled=0;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET students_finished = 1;
	
	
	DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
	    GET DIAGNOSTICS CONDITION 1
        @p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
        SELECT @p1 as RETURNED_SQLSTATE  , @p2 as MESSAGE_TEXT;
        ROLLBACK;
    END;
	
	
	 START TRANSACTION;
	
    open students_cursor;
    students_loop: LOOP
	
        
		
		FETCH students_cursor INTO workshop_reg_id_var,student_id_var,reg_type_var;
		
		
       
        IF students_finished = 1 THEN 
			LEAVE students_loop;
		END IF;
         SELECT concat('student ',(select name from users where id=student_id_var));

	
        
        
       if reg_type_var=2 THEN
  
select 
   
 (select count(*) from workshop_cues_watch where workshop_reg_id = workshop_reg_id_var) /
								  (select count(*)
								   from workshop_cues
								   where running_workshop_id = running_workshop_id_var) 
		   into watch_percent;
           
           
           
           
            update workshops_reg set cert_deserve=if(watch_percent>=(SELECT value from atc_config where title='workshop_watch_rate'),1,0) where id=workshop_reg_id_var;
       end if;
        
       
       
       
	END LOOP students_loop;
	
	select "All students finished";
	
		
	select if(trainer_online_percent,trainer_online_percent,if((select trainer_online_percent from users where id=running_workshops.trainer_id),(select trainer_online_percent from users where id=running_workshops.trainer_id),(select value from atc_config where title='trainer_online_percent'))),if(trainer_offline_percent,trainer_offline_percent,if((select trainer_offline_percent from users where id=running_workshops.trainer_id),(select trainer_offline_percent from users where id=running_workshops.trainer_id),(select value from atc_config where title='trainer_offline_percent'))) into percent_online_var,percent_offline_var from running_workshops where id=running_workshop_id_var;
	

	
    	select sum(amount) into tot_usd_offline from workshops_reg join accounting on workshops_reg.id=accounting.details_id where running_workshop_id=running_workshop_id_var and currency='d' and accounting.type_id=6 and reg_type=1 and cancelled=0 and workshops_reg.payment_confirmed=1 and amount>0;
        
	select sum(amount) into tot_usd_online from workshops_reg join accounting on workshops_reg.id=accounting.details_id where running_workshop_id=running_workshop_id_var and currency='d' and accounting.type_id=6 and reg_type=2 and cancelled=0 and workshops_reg.payment_confirmed=1 and amount>0;
    
	select sum(amount) into tot_sdg_offline from workshops_reg join accounting on workshops_reg.id=accounting.details_id where running_workshop_id=running_workshop_id_var and currency='s' and accounting.type_id=6 and reg_type=1 and cancelled=0 and workshops_reg.payment_confirmed=1 and amount>0;
    
	select sum(amount) into tot_sdg_online from workshops_reg join accounting on workshops_reg.id=accounting.details_id where running_workshop_id=running_workshop_id_var and currency='s' and accounting.type_id=6 and reg_type=2 and cancelled=0 and workshops_reg.payment_confirmed=1 and amount>0;
	
	SELECT concat("tot_sdg_online",tot_sdg_online);
    SELECT concat("tot_sdg_offline",tot_sdg_offline);
    SELECT concat("percent_online_var",percent_online_var);
    SELECT concat("percent_offline_var",percent_offline_var);
	update running_workshops set teacher_deserves_usd=(if(tot_usd_offline,tot_usd_offline,0)*percent_offline_var/100+if(tot_usd_online,tot_usd_online,0)*percent_online_var/100),teacher_deserves=(if(tot_sdg_offline,tot_sdg_offline,0)*percent_offline_var/100+if(tot_sdg_online,tot_sdg_online,0)*percent_online_var/100),	calculated=1,calculated_time=CURRENT_TIMESTAMP where id=running_workshop_id_var;
    
	
	COMMIT;
END$$

DROP PROCEDURE IF EXISTS `fixAliasNumbers`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `fixAliasNumbers` ()   BEGIN
declare finished,course_id_var,current_index,total_courses,id_var int DEFAULT 0;
  DECLARE runnings json;

 DECLARE courses_cursor CURSOR FOR SELECT id from courses;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET finished = 1;


	DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
	    GET DIAGNOSTICS CONDITION 1
        @p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
        SELECT @p1 as RETURNED_SQLSTATE  , @p2 as MESSAGE_TEXT;
        ROLLBACK;
    END;



	
	
	 START TRANSACTION;
      open courses_cursor;
    courses_loop: LOOP
     FETCH courses_cursor INTO course_id_var;
     
      if finished=1 THEN
     leave courses_loop;
     end if;
     SELECT 1;
     select json_arrayagg(id) into runnings from running_courses where course_id=course_id_var;
     set current_index=0;
     set total_courses=json_length(runnings);
     SELECT concat("current_index",current_index);
     SELECT concat("total_courses",total_courses);

     while current_index<total_courses DO
        set id_var=json_extract(runnings,concat("$[",current_index,"]"));
        
     	SELECT concat("current_index: ",current_index," id: ",id_var);
        
        update running_courses set alias = concat("G",current_index+1) where id=id_var;
        set current_index=current_index+1;
     end WHILE;
     END LOOP courses_loop;
	COMMIT;

    
end$$

DROP PROCEDURE IF EXISTS `getStudentsNames`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `getStudentsNames` (OUT `y` TEXT)   BEGIN
declare studentCount,finished int DEFAULT 0;
DECLARE n varchar(100) DEFAULT "";
DECLARE allNames text DEFAULT "";
DECLARE cur CURSOR for SELECT name from students_users;

DECLARE CONTINUE HANDLER FOR NOT FOUND set finished=1;
open cur;
myLoop: while finished=0 DO
FETCH cur into n;
set allNames=concat(allNames,' , ',n);
end while;
close cur;
set y=allNames;
end$$

DROP PROCEDURE IF EXISTS `longsetNotCreatedAccount`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `longsetNotCreatedAccount` (OUT `lng` INT, OUT `date1` VARCHAR(255), OUT `date2` VARCHAR(255))   BEGIN
DECLARE longest int DEFAULT 0;
declare temp varchar(255);
DECLARE arr json;
DECLARE i int DEFAULT 1;
declare x,y varchar(255);

SELECT json_arrayagg(created) into arr from students_users;
myLoop: while i<json_length(arr) DO
set x=substring(cast(json_extract(arr,concat('$[',i,']')) as char),2,19);
set y=substring(cast(json_extract(arr,concat('$[',i-1,']')) as char),2,19);
set temp=timestampdiff(second,y,x);
SELECT temp;
if temp>longest THEN
set longest=temp;
set date1=y;
set date2=x;
end if;
set i=i+1;
end while;
set lng=longest;
end$$

DROP PROCEDURE IF EXISTS `product`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `product` (IN `number` INT, OUT `pro` INT)   BEGIN
set pro=1;
myLoop: LOOP
set pro=pro*number;
set number=number-1;
if number=0 THEN
   LEAVE myLoop;
end if;
end loop;
end$$

DROP PROCEDURE IF EXISTS `SetVideosCuesForRange`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `SetVideosCuesForRange` (IN `path_min_var` INT, IN `path_max_var` INT)   BEGIN
    DECLARE finished,id_var,length_var,index_var int DEFAULT 0;
    DECLARE videos_cursor CURSOR FOR SELECT id,TIME_TO_SEC(length) from video_pathes where id>=path_min_var and id<=path_max_var;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET finished = 1;
	
	
	DECLARE EXIT HANDLER FOR SQLEXCEPTION 
