	    GET DIAGNOSTICS CONDITION 1
        @p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
        SELECT @p1 as RETURNED_SQLSTATE  , @p2 as MESSAGE_TEXT;
        ROLLBACK;
    END;
	SELECT 1;
	
	 START TRANSACTION;
	
    open videos_cursor;
    video_loop: LOOP
	
        
		
		FETCH videos_cursor INTO id_var,length_var;
