DROP PROCEDURE IF EXISTS `summer`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `summer` (IN `arr` JSON, OUT `tot` FLOAT)   BEGIN
DECLARE i,t int DEFAULT 0;
set i=0;
set t=0;
myLoop: LOOP
set t=t+json_extract(arr,concat("$[",i,"]"));
set i=i+1;
select tot;
if i=json_length(arr) THEN
   LEAVE myLoop;
end if;
end loop;
set tot=t;
end$$

DROP PROCEDURE IF EXISTS `user_session_charts`$$
CREATE DEFINER=`root`@`localhost` PROCEDURE `user_session_charts` (IN `user_id_var` INT)   select DATE_FORMAT(selected_date,"%Y-%m-%d") label,(SELECT sum(time_to_sec(timediff(finish_time,start_time)))/3600 FROM `sessions` WHERE  sessions.user_id =user_id_var and finish_time is not null and date(start_time) =selected_date GROUP BY DATE_FORMAT(start_time,"%Y-%m-%d")) y from (select selected_date from (select adddate('1970-01-01',t4*10000 + t3*1000 + t2*100 + t1*10 + t0) selected_date from (select 0 t0 union select 1 union select 2 union select 3 union select 4 union select 5 union select 6 union select 7 union select 8 union select 9) t0, (select 0 t1 union select 1 union select 2 union select 3 union select 4 union select 5 union select 6 union select 7 union select 8 union select 9) t1, (select 0 t2 union select 1 union select 2 union select 3 union select 4 union select 5 union select 6 union select 7 union select 8 union select 9) t2, (select 0 t3 union select 1 union select 2 union select 3 union select 4 union select 5 union select 6 union select 7 union select 8 union select 9) t3, (select 0 t4 union select 1 union select 2 union select 3 union select 4 union select 5 union select 6 union select 7 union select 8 union select 9) t4) v where selected_date between date(date_sub(now(),INTERVAL 1 month)) and CURRENT_DATE()) tmp$$

