DROP FUNCTION IF EXISTS `calcExam`$$
CREATE DEFINER=`root`@`localhost` FUNCTION `calcExam` (`course_reg_id` INT, `course_exam_id` INT) RETURNS INT(11) NO SQL BEGIN
    DECLARE finished,answer_id,loop_index,loop_count,correct_count INTEGER DEFAULT 0;
    DECLARE type varchar(255);
    DECLARE tot_degree,student_degree float DEFAULT 0;
    DECLARE student_answer text;
    DECLARE correct_answer text;

    DECLARE exam_cursor CURSOR FOR SELECT a.id,a.answer student_answer,q.answer correct_answer,type,q.degree
	FROM courses_exams_questions q
	LEFT JOIN courses_exams_answers a on q.id = a.courses_exams_questions_id and  a.course_reg_id=course_reg_id
	WHERE courses_exams_id= course_exam_id and (type='trueFalse' or type='circle' or type='output' or type='table');
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET finished = 1;
    
    open exam_cursor;
    checkAllAnswers:LOOP
		FETCH exam_cursor INTO answer_id,student_answer,correct_answer,type,tot_degree;
		
        IF finished = 1 THEN 
			LEAVE checkAllAnswers;
		END IF;
		
        IF type='trueFalse' or type='circle' or type='output' THEN
		update courses_exams_answers set degree=if(student_answer=correct_answer,tot_degree,0) where id=answer_id;
    ELSEIF type='table' THEN
       set loop_index=0;
       set correct_count=0;
       set loop_count=json_length(correct_answer);
       WHILE loop_index<loop_count DO
          if json_extract(student_answer,concat('$[',loop_index,']'))=json_extract(correct_answer,concat('$[',loop_index,']')) then
          set correct_count=correct_count+1;
          end if;
       END WHILE;
       update courses_exams_answers set degree=correct_count where id=answer_id;
    END IF;
        
	END LOOP checkAllAnswers;
    RETURN 0;
END$$

DROP FUNCTION IF EXISTS `copyPaymentIdToAccounting`$$
CREATE DEFINER=`root`@`localhost` FUNCTION `copyPaymentIdToAccounting` (`course_reg_id_var` INT, `payment_id_var` VARCHAR(255)) RETURNS INT(11)  BEGIN

update accounting set payment_id=payment_id_var where details_id=course_reg_id_var and type_id=1;
RETURN 5;

end$$

DROP FUNCTION IF EXISTS `courseCalculatable`$$
CREATE DEFINER=`root`@`localhost` FUNCTION `courseCalculatable` (`running_course_id_var` INT) RETURNS LONGTEXT CHARSET utf8mb4  begin
declare state,calcualted_var boolean DEFAULT 0;
DECLARE student_count,loop_count,loop_index,reason_code,students_did int DEFAULT 0;
DECLARE exams,projects,rtn,undone_projects,undone_exams json;
set rtn=json_object("status",1);
SELECT count(cr.id),(SELECT calcualted from running_courses where id=running_course_id_var) into student_count,calcualted_var from courses_reg cr where cr.running_course_id=running_course_id_var and cr.can_attend=1 and cr.cancelled=0;
set reason_code=0;
SELECT if(CURRENT_TIMESTAMP>rc.finish_time,1,0) into state from running_courses rc where id=running_course_id_var;
if state=0 THEN
set rtn=json_object("status",2);
ELSEIF calcualted_var=1 THEN
set rtn=json_object("status",3);
ELSE



select json_arrayagg(json_object("title",e.title,"checked",(select count(ec.degree) from courses_exams_check ec where ec.course_exam_id=e.id))) into exams from courses_exams e where e.running_course_id=running_course_id_var;

select json_arrayagg(json_object("title",p.title,"checked",(select count(pu.degree) from courses_projects_uploads pu where pu.courses_projects_id=p.id))) into projects from courses_projects p where p.running_course_id=running_course_id_var;



set loop_count=json_length(exams);
set state=1;
set loop_index=0;
set undone_exams="[]";
while loop_index<loop_count DO
   set students_did=json_extract(exams,concat("$[",loop_index,"].checked"));
   if students_did != student_count THEN
      set state=0;
      set undone_exams=json_array_append(undone_exams,"$",json_extract(exams,concat("$[",loop_index,"].title")));
   end if;
   set loop_index=loop_index+1;
end while;

if state = 0 THEN
	set rtn= json_object("status",0,"exams",undone_exams);
end if;


set loop_index=0;
set loop_count=json_length(projects);
set state=1;
set undone_projects="[]";
while loop_index<loop_count
DO
   set students_did=json_extract(projects,concat("$[",loop_index,"].checked"));
   if students_did != student_count THEN
      set state=0;
       set undone_projects=json_array_append(undone_projects,"$",json_extract(projects,concat("$[",loop_index,"].title")));
   end if;
   set loop_index=loop_index+1;
end while;
if state=0 THEN
   set rtn=json_set(rtn,"$.status",0);
   set rtn=json_set(rtn,"$.projects",undone_projects);
end if;



end if;

RETURN rtn;




end$$

