if service_type_id<=2 THEN
  SELECT alias into service_alias from courses join running_courses on running_courses.course_id=courses.id  where running_courses.id = subservice_record_id;
ELSEIF service_type_id<=4 THEN
  SELECT alias into service_alias from workshops join running_workshops on running_workshops.workshop_id=workshops.id where running_workshops.id=subservice_record_id; 

end if;
RETURN service_alias;
END$$

DROP FUNCTION IF EXISTS `getTax`$$
CREATE DEFINER=`root`@`localhost` FUNCTION `getTax` (`salary` DECIMAL(20,2)) RETURNS DECIMAL(20,2)  BEGIN
DECLARE remaining,tax,start_value_var,end_value_var,percentage_var decimal(20,2) DEFAULT 0.00;
DECLARE tax_levels_finished int DEFAULT 0;
DECLARE tax_cursor CURSOR for SELECT start_value,end_value,percentage from hr_tax_levels;

DECLARE CONTINUE HANDLER FOR NOT FOUND SET tax_levels_finished = 1;

SET remaining = salary;

OPEN tax_cursor;
tax_levels_loop:LOOP
FETCH tax_cursor into start_value_var,end_value_var,percentage_var;
  IF tax_levels_finished = 1 or remaining <= 0 THEN 
      LEAVE tax_levels_loop;
    END IF;
if remaining < (end_value_var - start_value_var) THEN
  set tax = tax + remaining * percentage_var/100;
  set remaining = 0;
else
  set tax = tax + (end_value_var - start_value_var)*percentage_var/100;
  set remaining = remaining - (end_value_var - start_value_var);
end if;
end loop tax_levels_loop;
RETURN tax;
end$$

