    DECLARE finished,id_var,length_var,index_var,cues_count_var int DEFAULT 0;
	
	
SELECT value into cues_count_var from atc_config where title='cues_count';

SELECT TIME_TO_SEC(length) into length_var from video_pathes where id=video_path_id_var;
        
        
