--
-- Triggers `cash_accounts`
--
DROP TRIGGER IF EXISTS `deleteCashAccount`;
DELIMITER $$
CREATE TRIGGER `deleteCashAccount` BEFORE DELETE ON `cash_accounts` FOR EACH ROW BEGIN
DECLARE total_transactions INT;
SELECT count(*) into total_transactions from transaction_details where id=OLD.level_three_chart_of_account_id;
IF total_transactions>0 THEN 
SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Cannot delete due to specific condition'; 
ELSE
DELETE from level_three_chart_of_accounts where id=OLD.level_three_chart_of_account_id;
end if; 
end
$$
DELIMITER ;
DROP TRIGGER IF EXISTS `insertCashAccount`;
DELIMITER $$
CREATE TRIGGER `insertCashAccount` BEFORE INSERT ON `cash_accounts` FOR EACH ROW BEGIN
    DECLARE account_code,accounts_length int DEFAULT 0;
    SELECT code into account_code from level_two_chart_of_accounts where id=(SELECT level_two_chart_of_account_id from subledger_parent_accounts where name_en=if(NEW.type='cash','Cash','Banks') );

    SELECT count(*) into accounts_length from level_three_chart_of_accounts where level_two_chart_of_account_id=(SELECT level_two_chart_of_account_id from subledger_parent_accounts where name_en=if(NEW.type='cash','Cash','Banks'));

    set account_code = account_code+accounts_length+1;
    set NEW.level_three_chart_of_account_id = LAST_INSERT_ID();
END
$$
DELIMITER ;
DROP TRIGGER IF EXISTS `updateCashAccount`;
DELIMITER $$
CREATE TRIGGER `updateCashAccount` AFTER UPDATE ON `cash_accounts` FOR EACH ROW BEGIN
    update level_three_chart_of_accounts set name=NEW.name,name_en=NEW.name_en where id=NEW.level_three_chart_of_account_id;

end
$$
DELIMITER ;

