--
-- Triggers `running_courses`
--
DROP TRIGGER IF EXISTS `after_insert_running_course`;
DELIMITER $$
CREATE TRIGGER `after_insert_running_course` AFTER INSERT ON `running_courses` FOR EACH ROW BEGIN
    DECLARE lecture_id INT;
    DECLARE done INT DEFAULT FALSE;
    DECLARE lecture_date DATE;
    
    -- Cursor to get all lectures for this course, ordered by id
    DECLARE lecture_cursor CURSOR FOR 
        SELECT id 
        FROM courses_lectures 
        WHERE course_id = NEW.course_id
        ORDER BY id ASC;

    -- Handler for end of cursor
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- Start date for first lecture
    SET lecture_date = DATE(NEW.start_time);

    OPEN lecture_cursor;

    lecture_loop: LOOP
        FETCH lecture_cursor INTO lecture_id;
        IF done THEN
            LEAVE lecture_loop;
        END IF;

        -- Skip lecture if it falls on Friday and running_course.isFriday = 1
        WHILE NEW.isFriday = 1 AND DAYOFWEEK(lecture_date) = 6 DO
            SET lecture_date = DATE_ADD(lecture_date, INTERVAL 1 DAY);
        END WHILE;

        -- Skip lecture if it falls on Saturday and running_course.isSaturday = 1
        WHILE NEW.isSaturday = 1 AND DAYOFWEEK(lecture_date) = 7 DO
            SET lecture_date = DATE_ADD(lecture_date, INTERVAL 1 DAY);
        END WHILE;

        -- Insert lecture into running_course_lecture
        VALUES (NEW.id, lecture_id, lecture_date, NOW(), NOW());

        -- Move to next day for next lecture
        SET lecture_date = DATE_ADD(lecture_date, INTERVAL 1 DAY);

    END LOOP;

    CLOSE lecture_cursor;
END
$$
DELIMITER ;

